        state.buffer_effective[14] = Span.init_diacritic_tone(c.first_base, c.first_diacritic, .level);
        state.buffer_effective[15] = Span.init_diacritic_tone(c.second_base, c.second_diacritic, .level);
        state.buffer_length = 16;

