247: const State = struct {
248:     // The effective buffer to process Vietnamese input. we will skip processing if the buffer
249:     // longer than 16.
250:     buffer_effective: [16]Span,
251:     // The maximum buffer length that the engine still keeps the effective buffer, after the maximum
252:     // value (255), we will reset the effective buffer and this value.
253:     buffer_length: u8 = 0,
254:     // The previous buffer length before State.add is called, used to calculate synthetic backspaces.
255:     buffer_length_previous: u8 = 0,
256:     // Mark the earliest position (inclusive) in buffer where we modified the span, will be used to
257:     // calculate backspaces and replacement characters.
258:     buffer_modification_index: ?u8 = null,
259:     // Mark the position (inclusive) in buffer where the engine stops Telex processing and appends
260:     // the remaining composition literally. Positions before literal_index were processed as Telex;
261:     // positions on or after literal_index form the literal tail. null means the whole current buffer
262:     // remains Telex-processable.
263:     literal_index: ?u8 = null,
264: 
265:     // Initialize the State on allocated memory.
266:     fn init(self: *State) void {
267:         self.* = .{
268:             .buffer_effective = undefined,
269:         };
270:     }
271: 
272:     fn add(self: *State, c: u8) void {
273:         // Only allow a-zA-Z.
274:         assert(isAlphabetic(c));
275: 
276:         if (self.literal_index) |literal_index| {
277:             // The literal_index value must be in range null or 0 -> 16 (buffer_effective length)
278:             // because we won't process Vietnamese input outside the buffer_effective.
279:             assert(literal_index <= self.buffer_effective.len);
280:             // The literal_index value must be less than buffer length.
281:             assert(literal_index < self.buffer_length);
282:         }
283: 
284:         // buffer_length conditions
285:         // 1. must be within buffer_effective length while the whole buffer is Telex-processable.
286:         // 2. could be more than buffer_effective after literal_index starts the literal tail.
287:         assert(self.buffer_length <= self.buffer_effective.len or self.literal_index != null);
288: 
289:         // Reset buffer_modification_index to start the new action.
290:         self.buffer_modification_index = null;
291: 
292:         switch (c) {
293:             'A', 'a' => {
294:                 if (self.literal_index != null or self.buffer_length == 0) {
295:                     // 1. Append literally when literal_index is set.
296:                     // 2. Append literal because no previous span existed. Continue Vietnamese
297:                     // processing on next input.
298:                     self.append_literal(c);
299:                     // Set modification index to null because we didn't modify any existing span.
300:                     self.buffer_modification_index = null;
301:                 } else if (self.buffer_effective_last().equals_ignore_case_tone(c, .empty)) {
302:                     // 3. Previous span is 'A' or 'a', apply circumflex.
303:                     const span_previous = self.buffer_effective[self.buffer_length - 1];
304:                     self.buffer_effective[self.buffer_length - 1] = Span.init_diacritic_tone(span_previous.base, .circumflex, span_previous.tone);
305:                     // Set modification index for calculating synthetic backspace.
306:                     self.buffer_modification_index = self.buffer_length - 1;
307:                 } else if (self.buffer_effective_last().equals_ignore_case_tone(c, .breve)) {
308:                     // 4. Previous span is 'Ă' or 'ă', override to circumflex.
309:                     const span_previous = self.buffer_effective[self.buffer_length - 1];
310:                     self.buffer_effective[self.buffer_length - 1] = Span.init_diacritic_tone(span_previous.base, .circumflex, span_previous.tone);
311:                     // Set modification index for calculating synthetic backspace.
312:                     self.buffer_modification_index = self.buffer_length - 1;
313:                 } else if (self.buffer_effective_last().equals_ignore_case_tone(c, .circumflex)) {
314:                     // 5. Previous span is 'Â' or 'â', cancel circumflex for previous span and append new literal span.
315:                     const span_previous = self.buffer_effective[self.buffer_length - 1];
316:                     self.buffer_effective[self.buffer_length - 1] = Span.init_diacritic_tone(span_previous.base, .empty, span_previous.tone);
317:                     // Set modification index for calculating synthetic backspace.
318:                     self.buffer_modification_index = self.buffer_length - 1;
319:                     // Start literal input from this position.
320:                     self.literal_index = self.buffer_length;
321:                     // Append literal 'A' or 'a'.
322:                     self.append_literal(c);
323:                 } else if (!self.buffer_effective_last().equals_ignore_case_diacritic_tone(c)) {
324:                     // 6. Append literal when previous span is not 'A', 'a' and its variants.
325:                     self.append_literal(c);
326:                     // No modification.
327:                     self.buffer_modification_index = null;
328:                 } else {
329:                     unreachable;
330:                 }
331:             },
332:             'C', 'c' => { // fill missing diacritic, e.g. cước.
333:                 if (self.literal_index != null or self.buffer_length < 2) {
334:                     // 1. Append literally when literal_index is set.
335:                     // 2. Append literal because no previous span existed. Continue Vietnamese
336:                     // processing on next input.
337:                     // 3. Buffer is less than 2 characters to start with.
338:                     self.append_literal(c);
