1967: test "expect State.add auto-fill missing horn in valid cases" {
1968:     // Arrange: starting pair shapes covering both auto-fill targets and all
1969:     // case combinations. `receiving_offset` marks which vowel in the pair
1970:     // gains horn (0 = first, 1 = second).
1971:     const PairCase = struct {
1972:         first_base: u8,
1973:         first_diacritic: Diacritic,
1974:         second_base: u8,
1975:         second_diacritic: Diacritic,
1976:         receiving_offset: u8,
1977:     };
1978:     const pair_cases = [_]PairCase{
1979:         // uơ pattern: first vowel is missing horn.
1980:         .{ .first_base = 'u', .first_diacritic = .empty, .second_base = 'o', .second_diacritic = .horn, .receiving_offset = 0 },
1981:         .{ .first_base = 'u', .first_diacritic = .empty, .second_base = 'O', .second_diacritic = .horn, .receiving_offset = 0 },
1982:         .{ .first_base = 'U', .first_diacritic = .empty, .second_base = 'o', .second_diacritic = .horn, .receiving_offset = 0 },
1983:         .{ .first_base = 'U', .first_diacritic = .empty, .second_base = 'O', .second_diacritic = .horn, .receiving_offset = 0 },
1984:         // ưo pattern: second vowel is missing horn.
1985:         .{ .first_base = 'u', .first_diacritic = .horn, .second_base = 'o', .second_diacritic = .empty, .receiving_offset = 1 },
1986:         .{ .first_base = 'u', .first_diacritic = .horn, .second_base = 'O', .second_diacritic = .empty, .receiving_offset = 1 },
1987:         .{ .first_base = 'U', .first_diacritic = .horn, .second_base = 'o', .second_diacritic = .empty, .receiving_offset = 1 },
1988:         .{ .first_base = 'U', .first_diacritic = .horn, .second_base = 'O', .second_diacritic = .empty, .receiving_offset = 1 },
1989:     };
1990: 
1991:     const triggers = [_]u8{ 'C', 'c', 'I', 'i', 'M', 'm', 'N', 'n', 'P', 'p', 'T', 't', 'U', 'u' };
1992: 
1993:     const tones = [_]Tone{ .level, .rising, .falling, .dipping_rising, .rising_glottalized, .falling_glottalized };
1994: 
1995:     // Linguistically valid one-tone syllables: a tone may sit on either vowel.
1996:     // Sweep both positions while the other vowel stays at .level. We do not
1997:     // fabricate double-toned syllables that the spec would not consider valid.
1998:     const tone_positions = [_]u8{ 0, 1 };
1999: 
2000:     // Cover both pair-at-start (no prefix) and pair-after-consonant variants
2001:     // to prove the rule looks at the last two spans regardless of buffer_length.
2002:     const prefix_lengths = [_]u8{ 0, 1 };
2003: 
2004:     for (pair_cases) |pc| {
2005:         for (triggers) |trig| {
2006:             for (tones) |tn| {
2007:                 for (tone_positions) |tpos| {
2008:                     for (prefix_lengths) |plen| {
2009:                         var state: State = undefined;
2010:                         state.init();
2011: 
2012:                         // Optional 'b' prefix to place the pair at index 1..2.
2013:                         if (plen == 1) {
2014:                             state.buffer_effective[0] = Span.init('b');
2015:                         }
2016: 
2017:                         const first_tone: Tone = if (tpos == 0) tn else .level;
2018:                         const second_tone: Tone = if (tpos == 1) tn else .level;
2019: 
2020:                         state.buffer_effective[plen] = Span.init_diacritic_tone(pc.first_base, pc.first_diacritic, first_tone);
2021:                         state.buffer_effective[plen + 1] = Span.init_diacritic_tone(pc.second_base, pc.second_diacritic, second_tone);
2022:                         state.buffer_length = plen + 2;
2023: 
2024:                         // Act
2025:                         state.add(trig);
2026: 
2027:                         // Assert
2028:                         const receiving_index = plen + pc.receiving_offset;
2029:                         try expectEqual(plen + 3, state.buffer_length);
2030:                         try expectEqual(receiving_index, state.buffer_modification_index);
2031:                         try expectEqual(null, state.literal_index);
2032: 
2033:                         // Prefix, when present, must be unchanged.
2034:                         if (plen == 1) {
2035:                             const sp_prefix = state.buffer_effective[0];
2036:                             try expectEqual(@as(u8, 'b'), sp_prefix.base);
2037:                             try expectEqual(.empty, sp_prefix.diacritic);
2038:                             try expectEqual(.level, sp_prefix.tone);
2039:                         }
2040: 
2041:                         // Both vowel spans must end with horn; case and tone preserved.
2042:                         const sp_first = state.buffer_effective[plen];
2043:                         try expectEqual(pc.first_base, sp_first.base);
2044:                         try expectEqual(.horn, sp_first.diacritic);
2045:                         try expectEqual(first_tone, sp_first.tone);
2046: 
2047:                         const sp_second = state.buffer_effective[plen + 1];
2048:                         try expectEqual(pc.second_base, sp_second.base);
2049:                         try expectEqual(.horn, sp_second.diacritic);
2050:                         try expectEqual(second_tone, sp_second.tone);
2051: 
2052:                         // The trigger character is appended literally.
2053:                         const sp_new = state.buffer_effective[plen + 2];
2054:                         try expectEqual(trig, sp_new.base);
2055:                         try expectEqual(.empty, sp_new.diacritic);
2056:                         try expectEqual(.level, sp_new.tone);
2057:                     }
2058:                 }
2059:             }
2060:         }
2061:     }
